SELECT * FROM (SELECT TRY_CAST("YEAR" AS INTEGER) AS year, TRY_CAST("MONTH_NUM" AS INTEGER) AS month, TRY_CAST(left(CAST("FLT_DATE" AS VARCHAR), 10) AS DATE) AS date, NULLIF("ENTITY_NAME", '') AS entity_name, NULLIF("ENTITY_TYPE", '') AS entity_type, TRY_CAST("FLT_ERT_1" AS DOUBLE) AS flt_ert_1, TRY_CAST("DLY_ERT_1" AS DOUBLE) AS dly_ert_1, TRY_CAST("DLY_ERT_A_1" AS DOUBLE) AS dly_ert_a_1, TRY_CAST("DLY_ERT_C_1" AS DOUBLE) AS dly_ert_c_1, TRY_CAST("DLY_ERT_D_1" AS DOUBLE) AS dly_ert_d_1, TRY_CAST("DLY_ERT_E_1" AS DOUBLE) AS dly_ert_e_1, TRY_CAST("DLY_ERT_G_1" AS DOUBLE) AS dly_ert_g_1, TRY_CAST("DLY_ERT_I_1" AS DOUBLE) AS dly_ert_i_1, TRY_CAST("DLY_ERT_M_1" AS DOUBLE) AS dly_ert_m_1, TRY_CAST("DLY_ERT_N_1" AS DOUBLE) AS dly_ert_n_1, TRY_CAST("DLY_ERT_O_1" AS DOUBLE) AS dly_ert_o_1, TRY_CAST("DLY_ERT_P_1" AS DOUBLE) AS dly_ert_p_1, TRY_CAST("DLY_ERT_R_1" AS DOUBLE) AS dly_ert_r_1, TRY_CAST("DLY_ERT_S_1" AS DOUBLE) AS dly_ert_s_1, TRY_CAST("DLY_ERT_T_1" AS DOUBLE) AS dly_ert_t_1, TRY_CAST("DLY_ERT_V_1" AS DOUBLE) AS dly_ert_v_1, TRY_CAST("DLY_ERT_W_1" AS DOUBLE) AS dly_ert_w_1, TRY_CAST("DLY_ERT_NA_1" AS DOUBLE) AS dly_ert_na_1, TRY_CAST("FLT_ERT_1_DLY" AS DOUBLE) AS flt_ert_1_dly, TRY_CAST("FLT_ERT_1_DLY_15" AS DOUBLE) AS flt_ert_1_dly_15 FROM "eurocontrol-ert-dly-fir") WHERE date IS NOT NULL
